body.script:
//
    const bareServerData = {
        "servers": [
            "https://rhw.one",
            "https://phantomnetwork.cloud",
            "https://artclass.site",
            "https://shuttleproxy.com"
        ]
    };

    function populateDropdown() {
        const select = document.getElementById('bareServerSelect');
        bareServerData.servers.forEach((server) => {
            const option = document.createElement('option');
            option.value = server;
            option.textContent = server;
            select.appendChild(option);
        });
    }

    // Dynamic Fetch & Intercept Execution Method
    async function loadProxyService() {
        try {
            const cdnWorkerUrl = 'https://cdn.jsdelivr.net/gh/zaka13alt/uvsvg@main/sw.js';
            console.log('Fetching main proxy core from jsDelivr...');

            const response = await fetch(cdnWorkerUrl);
            const scriptText = await response.text();

            // Intercept the browser's worker registration method directly
            const originalRegister = navigator.serviceWorker.register;
            navigator.serviceWorker.register = async function(url, options) {
                console.log("Intercepted registration attempt. Scope target:", options.scope);

                // Injecting the raw downloaded jsDelivr configuration text into local scope execution
                const fallbackBlob = new Blob([
                    `importScripts('${cdnWorkerUrl}');`
                ], { type: 'text/javascript' });

                // Creates an internal script proxy configuration mapping to bypass path limits
                const dummyWorkerUrl = URL.createObjectURL(fallbackBlob);
                return originalRegister.call(navigator, dummyWorkerUrl, { scope: options.scope || '/uv/service/' });
            };

            // Fallback fallback triggering standard registration under local scope rules
            if ('serviceWorker' in navigator) {
                navigator.serviceWorker.register('/uv/service/sw.js', { scope: '/uv/service/' })
                .then(() => console.log("Proxy worker context verified and bound."))
                .catch(err => console.warn("Interception hook applied. Waiting for request initialization...", err));
            }

        } catch (err) {
            console.error("Failed to map the remote worker execution pipeline:", err);
        }
    }

    window.addEventListener('load', () => {
        populateDropdown();
        loadProxyService();
    });
//
